373→        let cache = BehaviorMapCache::new(cache_dir.clone()).unwrap();
374→
375→        // Write JSON without nondeterministic_fields (simulates old cache format).
376→        let json = r#"{"function_id":"oldFunc","behaviors":[]}"#;
377→        std::fs::write(cache_dir.join("oldFunc.json"), json).unwrap();
378→
379→        let loaded = cache.load("oldFunc").unwrap().unwrap();
380→        assert!(loaded.nondeterministic_fields.is_empty());
381→    }
