  1→//! Disk cache for [`FunctionAnalysis`] results, enabling fast re-analysis of unchanged files.
  2→//!
  3→//! Each source file's analysis results are cached keyed by `(file_path, content_hash)`.
  4→//! On lookup, an mtime fast-path avoids re-hashing when the file hasn't been touched.
  5→//! A protocol version is stored with each entry — version bumps invalidate all cached data.
  6→
  7→use std::fs;
  8→use std::path::{Path, PathBuf};
  9→use std::time::SystemTime;
 10→
 11→use serde::{Deserialize, Serialize};
 12→use sha2::{Digest, Sha256};
 13→
 14→use crate::cache::CacheError;
 15→use crate::protocol::{FunctionAnalysis, PROTOCOL_VERSION};
 16→
 17→/// A single cached analysis entry for one source file.
 18→#[derive(Debug, Serialize, Deserialize)]
 19→struct AnalysisCacheEntry {
 20→    /// Hex-encoded SHA-256 of the file contents at the time of caching.
 21→    content_hash: String,
 22→    /// File modification time in seconds since the Unix epoch.
 23→    mtime_secs: i64,
 24→    /// Protocol version used when the analysis was produced.
 25→    protocol_version: String,
 26→    /// The cached analysis results.
 27→    analyses: Vec<FunctionAnalysis>,
 28→}
 29→
 30→/// Disk-backed cache for storing and loading [`FunctionAnalysis`] results.
 31→#[derive(Debug)]
 32→pub struct AnalysisCache {
 33→    cache_dir: PathBuf,
 34→}
 35→
 36→impl AnalysisCache {
 37→    /// Create a new analysis cache backed by the given directory.
 38→    ///
 39→    /// Creates the directory (and parents) if it doesn't exist.
 40→    pub fn new(cache_dir: PathBuf) -> Result<Self, CacheError> {
 41→        fs::create_dir_all(&cache_dir)?;
 42→        Ok(Self { cache_dir })
 43→    }
 44→
 45→    /// Look up cached analysis results for a source file.
 46→    ///
 47→    /// Returns `Ok(Some(analyses))` on cache hit, `Ok(None)` on cache miss.
 48→    /// Uses an mtime fast-path: if the file's mtime matches the cached mtime,
 49→    /// the content hash is not recomputed.
 50→    pub fn lookup(&self, file_path: &Path) -> Result<Option<Vec<FunctionAnalysis>>, CacheError> {
 51→        let cache_file = self.cache_path_for(file_path);
 52→
 53→        let contents = match fs::read_to_string(&cache_file) {
 54→            Ok(c) => c,
 55→            Err(e) if e.kind() == std::io::ErrorKind::NotFound => return Ok(None),
 56→            Err(e) => return Err(CacheError::Io(e)),
 57→        };
 58→
 59→        let mut entry: AnalysisCacheEntry = serde_json::from_str(&contents)?;
 60→
 61→        // Protocol version mismatch invalidates the cache.
 62→        if entry.protocol_version != PROTOCOL_VERSION {
 63→            return Ok(None);
 64→        }
 65→
 66→        let file_mtime = mtime_secs(file_path)?;
 67→
 68→        // Fast-path: mtime unchanged means file content hasn't changed.
 69→        if file_mtime == entry.mtime_secs {
 70→            return Ok(Some(entry.analyses));
 71→        }
 72→
 73→        // Slow path: mtime differs — compute content hash to check for real changes.
 74→        let current_hash = sha256_file(file_path)?;
 75→
 76→        if current_hash == entry.content_hash {
 77→            // File was touched but content is identical. Update the cached mtime
 78→            // so future lookups hit the fast-path.
 79→            entry.mtime_secs = file_mtime;
 80→            let json = serde_json::to_string_pretty(&entry)?;
 81→            let tmp = cache_file.with_extension("json.tmp");
 82→            fs::write(&tmp, json)?;
 83→            fs::rename(&tmp, &cache_file)?;
 84→            return Ok(Some(entry.analyses));
 85→        }
 86→
 87→        // Content actually changed — cache miss.
 88→        Ok(None)
 89→    }
 90→
 91→    /// Store analysis results for a source file.
 92→    pub fn store(
 93→        &self,
 94→        file_path: &Path,
 95→        analyses: &[FunctionAnalysis],
 96→    ) -> Result<(), CacheError> {
 97→        let content_hash = sha256_file(file_path)?;
 98→        let mtime_secs = mtime_secs(file_path)?;
 99→
100→        let entry = AnalysisCacheEntry {
101→            content_hash,
102→            mtime_secs,
103→            protocol_version: PROTOCOL_VERSION.to_string(),
104→            analyses: analyses.to_vec(),
105→        };
106→
107→        let cache_file = self.cache_path_for(file_path);
108→        let json = serde_json::to_string_pretty(&entry)?;
109→        let tmp = cache_file.with_extension("json.tmp");
110→        fs::write(&tmp, &json)?;
111→        fs::rename(&tmp, &cache_file)?;
112→
113→        Ok(())
114→    }
115→
116→    /// Remove all cached analysis entries.
117→    pub fn clear(&self) -> Result<(), CacheError> {
118→        if self.cache_dir.exists() {
119→            fs::remove_dir_all(&self.cache_dir)?;
120→            fs::create_dir_all(&self.cache_dir)?;
121→        }
122→        Ok(())
123→    }
124→
125→    /// Default analysis cache directory: `<project_root>/.shatter/cache/analysis/`.
126→    pub fn default_dir(project_root: &Path) -> PathBuf {
127→        project_root
128→            .join(".shatter")
129→            .join("cache")
130→            .join("analysis")
131→    }
132→
133→    /// Compute the cache file path for a given source file path.
134→    ///
135→    /// Uses SHA-256 of the file path string as the filename to avoid
136→    /// issues with path separators and special characters.
137→    fn cache_path_for(&self, file_path: &Path) -> PathBuf {
138→        let path_str = file_path.to_string_lossy();
139→        let hash = hex_sha256(path_str.as_bytes());
140→        self.cache_dir.join(format!("{hash}.json"))
141→    }
142→}
143→
144→/// Compute hex-encoded SHA-256 of a byte slice.
145→fn hex_sha256(data: &[u8]) -> String {
146→    let mut hasher = Sha256::new();
147→    hasher.update(data);
148→    format!("{:x}", hasher.finalize())
149→}
150→
151→/// Compute hex-encoded SHA-256 of a file's contents.
152→fn sha256_file(path: &Path) -> Result<String, CacheError> {
153→    let contents = fs::read(path)?;
154→    Ok(hex_sha256(&contents))
155→}
156→
157→/// Get a file's modification time as seconds since the Unix epoch.
158→fn mtime_secs(path: &Path) -> Result<i64, CacheError> {
159→    let metadata = fs::metadata(path)?;
160→    let mtime = metadata.modified()?;
161→    let duration = mtime
162→        .duration_since(SystemTime::UNIX_EPOCH)
163→        .unwrap_or_default();
164→    Ok(duration.as_secs() as i64)
165→}
