213→    #[test]
214→    fn cache_hit_returns_cached_analysis() {
215→        let dir = tempfile::tempdir().unwrap();
216→        let cache_dir = dir.path().join("cache");
217→        let cache = AnalysisCache::new(cache_dir).unwrap();
218→
219→        let src = create_source_file(dir.path(), "test.ts", "function add(a, b) { return a + b; }");
220→        let analyses = sample_analyses();
221→
222→        cache.store(&src, &analyses).unwrap();
223→        let result = cache.lookup(&src).unwrap();
224→
225→        assert!(result.is_some());
226→        let cached = result.unwrap();
227→        assert_eq!(cached.len(), 1);
228→        assert_eq!(cached[0].name, "add");
229→        assert_eq!(cached[0].params.len(), 2);
